Read this component with multiple hooks. What does it do, and in what order do things happen when the user first visits the page?

```jsx
function UserDashboard() {
  const { user } = useContext(AuthContext);
  const [repos, setRepos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sortBy, setSortBy] = useState('updated');

  useEffect(() => {
    if (!user) return;
    setLoading(true);
    fetch(`/api/users/${user.id}/repos?sort=${sortBy}`)
      .then(res => res.json())
      .then(data => {
        setRepos(data);
        setLoading(false);
      });
  }, [user, sortBy]);

  useEffect(() => {
    document.title = `${user?.name || 'User'}'s Repos`;
  }, [user]);

  if (!user) return <p>Please log in</p>;
  if (loading) return <Spinner />;

  return (
    <div>
      <h1>{user.name}'s Repositories</h1>
      <select value={sortBy} onChange={e => setSortBy(e.target.value)}>
        <option value="updated">Recently Updated</option>
        <option value="stars">Most Stars</option>
      </select>
      {repos.map(repo => (
        <RepoCard key={repo.id} repo={repo} />
      ))}
    </div>
  );
}
```

Find the infinite loop in this component. What is causing it, and what is the fix?

```jsx
function LiveChat({ roomId }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');

  useEffect(() => {
    fetch(`/api/rooms/${roomId}/messages`)
      .then(res => res.json())
      .then(data => setMessages(data));
  });

  function handleSend() {
    const newMessage = { text: input, timestamp: Date.now() };
    setMessages([...messages, newMessage]);
    setInput('');
  }

  return (
    <div>
      {messages.map((msg, i) => (
        <p key={i}>{msg.text}</p>
      ))}
      <input value={input} onChange={e => setInput(e.target.value)} />
      <button onClick={handleSend}>Send</button>
    </div>
  );
}
```

