You are reviewing AI-generated code for an e-commerce site. The client reports: "Adding an item to the cart works, but removing an item does nothing." What is wrong with the remove function?

```jsx
function ShoppingCart() {
  const [items, setItems] = useState([
    { id: 1, name: 'Keyboard', price: 79 },
    { id: 2, name: 'Mouse', price: 49 },
  ]);

  function addItem(newItem) {
    setItems(prev => [...prev, newItem]);
  }

  function removeItem(id) {
    const index = items.findIndex(i => i.id === id);
    items.splice(index, 1);
    setItems(items);
  }

  const total = items.reduce((sum, item) => sum + item.price, 0);

  return (
    <div>
      {items.map(item => (
        <div key={item.id}>
          <span>{item.name} - ${item.price}</span>
          <button onClick={() => removeItem(item.id)}>Remove</button>
        </div>
      ))}
      <p>Total: ${total}</p>
    </div>
  );
}
```

What does the custom hook return, and what happens when `roomId` changes?

```jsx
function useChatMessages(roomId) {
  const [messages, setMessages] = useState([]);
  const [isConnected, setIsConnected] = useState(false);

  useEffect(() => {
    const ws = new WebSocket(`wss://chat.example.com/${roomId}`);
    ws.onopen = () => setIsConnected(true);
    ws.onmessage = (event) => {
      setMessages(prev => [...prev, JSON.parse(event.data)]);
    };

    return () => {
      ws.close();
      setIsConnected(false);
      setMessages([]);
    };
  }, [roomId]);

  return { messages, isConnected };
}
```
